  1→import { useState, useRef, useCallback, useMemo, useEffect } from 'react';
  2→import { userHomeCoords, HOME_SCALE, GUEST_SCALE } from '../utils/starUtils';
  3→
  4→const useUniverseCamera = (userId, hasOwnPosts) => {
  5→    const stageRef = useRef(null);
  6→    const dragStartRef = useRef(null);
  7→    const lastPinchDist = useRef(null);
  8→    const isPinching = useRef(false);
  9→    const hasAdjustedZoom = useRef(false);
 10→
 11→    const [stageSize, setStageSize] = useState({
 12→        width: window.innerWidth,
 13→        height: window.innerHeight,
 14→    });
 15→
 16→    const initialCamera = useMemo(() => {
 17→        if (!userId) return { x: 0, y: 0 };
 18→        return userHomeCoords(userId);
 19→    }, [userId]);
 20→
 21→    // Start logged-in users at HOME_SCALE; will adjust after first fetch if no posts
 22→    const initialZoom = useMemo(() => (userId ? HOME_SCALE : GUEST_SCALE), [userId]);
 23→
 24→    const [camera, setCamera] = useState(initialCamera);
 25→    const [zoom, setZoom] = useState(initialZoom);
 26→    const [isDragging, setIsDragging] = useState(false);
 27→
 28→    // If logged-in user has no posts, zoom out so they can see other galaxies
 29→    useEffect(() => {
 30→        if (hasAdjustedZoom.current) return;
 31→        if (hasOwnPosts === null) return; // still loading
 32→        if (!userId) return; // guests already at GUEST_SCALE
 33→        if (!hasOwnPosts) {
 34→            hasAdjustedZoom.current = true;
 35→            setCamera({ x: 0, y: 0 });
 36→            setZoom(GUEST_SCALE);
 37→        } else {
 38→            hasAdjustedZoom.current = true;
 39→        }
 40→    }, [hasOwnPosts, userId]);
 41→
 42→    // Resize
 43→    useEffect(() => {
 44→        const onResize = () => setStageSize({ width: window.innerWidth, height: window.innerHeight });
 45→        window.addEventListener('resize', onResize);
 46→        return () => window.removeEventListener('resize', onResize);
 47→    }, []);
 48→
 49→    // Center world coords (for display)
 50→    const centerWorld = useMemo(() => ({
 51→        x: Math.round(camera.x),
 52→        y: Math.round(camera.y),
 53→    }), [camera]);
 54→
 55→    // Layer transform helper
 56→    const getLayerProps = useCallback((parallaxFactor) => ({
 57→        x: stageSize.width / 2 - camera.x * parallaxFactor * zoom,
 58→        y: stageSize.height / 2 - camera.y * parallaxFactor * zoom,
 59→        scaleX: zoom,
 60→        scaleY: zoom,
 61→    }), [camera, zoom, stageSize]);
 62→
 63→    // Viewport bounds at parallax 1.0 (for data fetching)
 64→    const getViewportBounds = useCallback(() => {
 65→        const halfW = (stageSize.width / 2) / zoom;
 66→        const halfH = (stageSize.height / 2) / zoom;
 67→        const pad = 200 / zoom;
 68→        return {
 69→            minX: camera.x - halfW - pad,
 70→            maxX: camera.x + halfW + pad,
 71→            minY: camera.y - halfH - pad,
 72→            maxY: camera.y + halfH + pad,
 73→        };
 74→    }, [camera, zoom, stageSize]);
 75→
 76→    // --- Drag handling (Stage is NOT draggable) ---
 77→    const handleMouseDown = useCallback((e) => {
 78→        // Only left button for mouse
 79→        if (e.evt.button !== undefined && e.evt.button !== 0) return;
 80→        dragStartRef.current = {
 81→            pointerX: e.evt.clientX ?? e.evt.touches?.[0]?.clientX,
 82→            pointerY: e.evt.clientY ?? e.evt.touches?.[0]?.clientY,
 83→            camX: camera.x,
 84→            camY: camera.y,
 85→        };
 86→        setIsDragging(true);
 87→    }, [camera]);
 88→
 89→    const handleMouseMove = useCallback((e) => {
 90→        if (!dragStartRef.current) return;
 91→        if (isPinching.current) return;
 92→        const px = e.evt.clientX ?? e.evt.touches?.[0]?.clientX;
 93→        const py = e.evt.clientY ?? e.evt.touches?.[0]?.clientY;
 94→        if (px == null || py == null) return;
 95→        const dx = (px - dragStartRef.current.pointerX) / zoom;
 96→        const dy = (py - dragStartRef.current.pointerY) / zoom;
 97→        setCamera({
 98→            x: dragStartRef.current.camX - dx,
 99→            y: dragStartRef.current.camY - dy,
100→        });
101→    }, [zoom]);
102→
103→    const handleMouseUp = useCallback(() => {
104→        dragStartRef.current = null;
105→        setIsDragging(false);
106→        isPinching.current = false;
107→        lastPinchDist.current = null;
108→    }, []);
109→
110→    // --- Wheel zoom ---
111→    const handleWheel = useCallback((e) => {
112→        e.evt.preventDefault();
113→        const stage = stageRef.current;
114→        if (!stage) return;
115→
116→        const pointer = stage.getPointerPosition();
117→        if (!pointer) return;
118→
119→        const screenCenterX = stageSize.width / 2;
120→        const screenCenterY = stageSize.height / 2;
121→
122→        const scaleBy = 1.08;
123→        const direction = e.evt.deltaY > 0 ? -1 : 1;
124→        const oldZoom = zoom;
125→        const newZoom = Math.min(Math.max(
126→            direction > 0 ? oldZoom * scaleBy : oldZoom / scaleBy,
127→            0.02
128→        ), 5);
129→
130→        // World point under cursor before zoom
131→        const worldX = camera.x + (pointer.x - screenCenterX) / oldZoom;
132→        const worldY = camera.y + (pointer.y - screenCenterY) / oldZoom;
133→
134→        // Adjust camera so same world point stays under cursor
135→        setCamera({
136→            x: worldX - (pointer.x - screenCenterX) / newZoom,
137→            y: worldY - (pointer.y - screenCenterY) / newZoom,
138→        });
139→        setZoom(newZoom);
140→    }, [zoom, camera, stageSize]);
141→
142→    // --- Touch / Pinch ---
143→    const handleTouchMove = useCallback((e) => {
144→        const touch = e.evt;
145→        if (touch.touches.length === 2) {
146→            // Pinch zoom
147→            isPinching.current = true;
148→            touch.preventDefault();
149→
150→            const t1 = touch.touches[0];
151→            const t2 = touch.touches[1];
152→            const dist = Math.hypot(t2.clientX - t1.clientX, t2.clientY - t1.clientY);
153→
154→            if (lastPinchDist.current === null) {
155→                lastPinchDist.current = dist;
156→                return;
157→            }
158→
159→            const oldZoom = zoom;
160→            const newZoom = Math.min(Math.max(oldZoom * (dist / lastPinchDist.current), 0.02), 5);
161→            lastPinchDist.current = dist;
162→
163→            const centerX = (t1.clientX + t2.clientX) / 2;
164→            const centerY = (t1.clientY + t2.clientY) / 2;
165→            const screenCenterX = stageSize.width / 2;
166→            const screenCenterY = stageSize.height / 2;
167→
168→            const worldX = camera.x + (centerX - screenCenterX) / oldZoom;
169→            const worldY = camera.y + (centerY - screenCenterY) / oldZoom;
170→
171→            setCamera({
172→                x: worldX - (centerX - screenCenterX) / newZoom,
173→                y: worldY - (centerY - screenCenterY) / newZoom,
174→            });
175→            setZoom(newZoom);
176→        } else if (touch.touches.length === 1 && !isPinching.current) {
177→            // Single finger drag — handled by mouseMove logic
178→            handleMouseMove(e);
179→        }
180→    }, [zoom, camera, stageSize, handleMouseMove]);
181→
182→    const handleTouchEnd = useCallback(() => {
183→        lastPinchDist.current = null;
184→        if (isPinching.current) {
185→            isPinching.current = false;
186→            dragStartRef.current = null;
187→        }
188→    }, []);
189→
190→    const stageEvents = useMemo(() => ({
191→        onMouseDown: handleMouseDown,
192→        onMouseMove: handleMouseMove,
193→        onMouseUp: handleMouseUp,
194→        onWheel: handleWheel,
195→        onTouchStart: handleMouseDown,
196→        onTouchMove: handleTouchMove,
197→        onTouchEnd: handleTouchEnd,
198→    }), [handleMouseDown, handleMouseMove, handleMouseUp, handleWheel, handleTouchMove, handleTouchEnd]);
199→
200→    // Google Maps-style fly-to: zoom out → pan → zoom in (parabolic arc)
201→    const flyAnimRef = useRef(null);
202→
203→    const flyTo = useCallback((targetX, targetY, targetZoom) => {
204→        if (flyAnimRef.current) cancelAnimationFrame(flyAnimRef.current);
205→
206→        const startX = camera.x;
207→        const startY = camera.y;
208→        const startZoom = zoom;
209→
210→        // Distance determines how far to zoom out and how long the flight takes
211→        const dist = Math.hypot(targetX - startX, targetY - startY);
212→
213→        // Scale duration with distance — clamp between 800ms and 2000ms
214→        const duration = Math.min(2000, Math.max(800, 400 + dist * 0.08));
215→
216→        // The "peak altitude" — zoom out proportional to travel distance
217→        // Farther trips zoom out more; short trips barely zoom out at all
218→        const minZoom = Math.min(startZoom, targetZoom);
219→        const peakZoomOut = Math.max(
220→            minZoom * 0.15,
221→            minZoom - dist * 0.00008
222→        );
223→        // Never zoom out beyond 0.01
224→        const midZoom = Math.max(0.01, Math.min(peakZoomOut, minZoom * 0.6));
225→
226→        const startTime = performance.now();
227→
228→        // Smooth ease — slow at start and end, fast in the middle
229→        const easeInOut = (t) => t < 0.5
230→            ? 4 * t * t * t
231→            : 1 - Math.pow(-2 * t + 2, 3) / 2;
232→
233→        const animate = (now) => {
234→            const elapsed = now - startTime;
235→            const raw = Math.min(elapsed / duration, 1);
236→            const t = easeInOut(raw);
237→
238→            // Pan linearly with the eased time
239→            const cx = startX + (targetX - startX) * t;
240→            const cy = startY + (targetY - startY) * t;
241→
242→            // Parabolic zoom: start → midZoom at t=0.5 → targetZoom at t=1
243→            // z(t) = a*t^2 + b*t + c, passing through (0,startZoom), (0.5,midZoom), (1,targetZoom)
244→            const a = 2 * startZoom - 4 * midZoom + 2 * targetZoom;
245→            const b = -3 * startZoom + 4 * midZoom - targetZoom;
246→            const c = startZoom;
247→            const z = a * t * t + b * t + c;
248→
249→            setCamera({ x: cx, y: cy });
250→            setZoom(Math.max(0.01, z));
251→
252→            if (raw < 1) {
253→                flyAnimRef.current = requestAnimationFrame(animate);
254→            } else {
255→                flyAnimRef.current = null;
256→            }
257→        };
258→
259→        flyAnimRef.current = requestAnimationFrame(animate);
260→    }, [camera, zoom]);
261→
262→    return {
263→        stageRef,
264→        stageSize,
265→        camera,
266→        zoom,
267→        isDragging,
268→        centerWorld,
269→        getLayerProps,
270→        getViewportBounds,
271→        stageEvents,
272→        flyTo,
273→    };
274→};
275→
276→export default useUniverseCamera;
